{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires relating the observed exciton binding energy to the effective Rydberg constant and then calculating the energy level for a specific principal quantum number n=3.",
  "helpers": [
    {
      "label": "calculate_binding_energy",
      "instructions": "Determine the binding energy of the 1s exciton by calculating the difference between the band gap and the energy of the 1s exciton peak. Ensure the binding energy is expressed as a positive value representing the energy required to dissociate the exciton."
    },
    {
      "label": "derive_rydberg_constant",
      "instructions": "Using the binding energy of the 1s state (n=1) and the hydrogenic model formula E_n = -Ry_eff / n^2, solve for the effective Rydberg energy (Ry_eff). Note that the binding energy E_b = Ry_eff / 1^2."
    },
    {
      "label": "calculate_n3_energy_level",
      "instructions": "Calculate the energy level for the n=3 state using the formula E_n = -Ry_eff / n^2. Pay strict attention to the sign convention: the energy level relative to the conduction band edge should be negative, representing a bound state."
    }
  ],
  "synthesis_brief": "Combine the results by taking the effective Rydberg constant derived from the 1s binding energy and applying it to the n=3 state formula. The final answer must be the specific energy value for n=3, including the correct negative sign to indicate a bound state relative to the band edge."
}

